        { type: "tool", tool: "write", callID: "call_8548492a47754afea348108a", state: {"status": "completed", "input": {"filePath": "/root/rocm-potter/kernels/attention_forward/ported.hip", "content": "#include <hip/hip_runtime.h>\n#include <hip/hip_vector_types.h>\n#include <hipblas/hipblas.h>\n#include <cstdio>\n#include <cmath>\n#include <cstring>\n\n// ============================================================\n// Kernel Configuration\n// ============================================================\n// SUB_GROUP_SIZE: tiling constant for loop unrolling (NOT hardware wavefront size)\n// On gfx942, hardware wavefront = 64. This constant is purely for loop tiling.\nconstexpr int SUB_GROUP_SIZE = 32;\nconstexpr int QUERY_TILE = 64;   // Query positions per block\nconstexpr int KEY_TILE = 64;     // Key positions per K/V tile in LDS\n\n// ============================================================\n// Attention Forward Kernel (Flash-Attention Style)\n// ============================================================\n// Each block processes one (batch, head, query_tile) combination.\n// Grid: B * n_head * num_query_tiles\n// Block: QUERY_TILE threads (1 wavefront on CDNA)\n//\n// LDS layout (must fit in 64 KiB on gfx942):\n//   s_KV:  [KEY_TILE * HEAD_SIZE]          — K tile, then V tile (reused)\n//   s_att: [QUERY_TILE * (KEY_TILE + 1)]    — attention scores (+1 padding for bank conflicts)\n//\n// For HEAD_SIZE=64, KEY_TILE=64, QUERY_TILE=64:\n//   s_KV  = 64 * 64 * 4 = 16,384 bytes = 16 KiB\n//   s_att = 64 * 65 * 4 = 16,640 bytes ≈ 16.3 KiB\n//   Total = 32.3 KiB < 64 KiB ✓\n//\n// Each thread keeps Q vector and output accumulator in registers:\n//   q_vec[HEAD_SIZE]  — QUERY_TILE * HEAD_SIZE floats in registers\n//   o_acc[HEAD_SIZE]  — QUERY_TILE * HEAD_SIZE floats in registers\n//   row_max, row_sum  — online softmax state\n\ntemplate<int HEAD_SIZE>\n__global__ void __launch_bounds__(QUERY_TILE, 2)\nattention_forward_kernel(\n    const float* __restrict__ Q,     // [B, T, n_head, head_size]\n    const float* __restrict__ K,     // [B, T, n_head, head_size]\n    const float* __restrict__ V,     // [B, T, n_head, head_size]\n    float* __restrict__ O,           // [B, T, n_head, head_size]\n    const int B, const int T, const int n_head,\n    const float scale\n) {\n    // Shared memory layout\n    extern __shared__ float s_mem[];\n    float* s_KV  = s_mem;                                       // [KEY_TILE, HEAD_SIZE]\n    float* s_att = s_mem + KEY_TILE * HEAD_SIZE;                // [QUERY_TILE, KEY_TILE+1] padded\n\n    const int tid = threadIdx.x;\n    const int bid = blockIdx.x;\n\n    // Decode block index → (batch, head, query_tile)\n    const int num_query_tiles = (T + QUERY_TILE - 1) / QUERY_TILE;\n    const int total_blocks = B * n_head * num_query_tiles;\n    if (bid >= total_blocks) return;\n\n    const int query_tile_idx = bid % num_query_tiles;\n    const int head_idx       = (bid / num_query_tiles) % n_head;\n    const int batch_idx      = bid / (num_query_tiles * n_head);\n    const int query_start    = query_tile_idx * QUERY_TILE;\n\n    // Local query index within this tile\n    const int q_local  = tid;\n    const int global_q = query_start + q_local;\n    const bool valid_q = (q_local < QUERY_TILE && global_q < T);\n\n    // Strides for [B, T, n_head, head_size] layout\n    const int head_stride = HEAD_SIZE;\n    const int t_stride    = n_head * HEAD_SIZE;\n    const int b_stride    = T * t_stride;\n\n    // Base pointers for this (batch, head)\n    const float* Q_bh = Q + batch_idx * b_stride + head_idx * head_stride;\n    const float* K_bh = K + batch_idx * b_stride + head_idx * head_stride;\n    const float* V_bh = V + batch_idx * b_stride + head_idx * head_stride;\n    float*       O_bh = O + batch_idx * b_stride + head_idx * head_stride;\n\n    // Load Q vector into registers\n    float q_vec[HEAD_SIZE];\n    if (valid_q) {\n        #pragma unroll\n        for (int d = 0; d < HEAD_SIZE; d++) {\n            q_vec[d] = Q_bh[global_q * t_stride + d];\n        }\n    }\n\n    // Online softmax accumulators\n    float row_max = -HUGE_VALF;\n    float row_sum = 0.0f;\n    float o_acc[HEAD_SIZE];\n    #pragma unroll\n    for (int d = 0; d < HEAD_SIZE; d++) {\n        o_acc[d] = 0.0f;\n    }\n\n    // Iterate over key tiles\n    const int num_key_tiles = (T + KEY_TILE - 1) / KEY_TILE;\n\n    for (int kt = 0; kt < num_key_tiles; kt++) {\n        const int key_start = kt * KEY_TILE;\n\n        // ---- Phase 1: Load K tile into s_KV ----\n        for (int i = tid; i < KEY_TILE * HEAD_SIZE; i += QUERY_TILE) {\n            const int k_local = i / HEAD_SIZE;\n            const int d       = i % HEAD_SIZE;\n            const int global_k = key_start + k_local;\n            s_KV[i] = (global_k < T) ? K_bh[global_k * t_stride + d] : 0.0f;\n        }\n        __syncthreads();\n\n        // ---- Phase 2: Compute attention scores Q·K^T for this tile ----\n        if (valid_q) {\n            for (int k_local = 0; k_local < KEY_TILE; k_local++) {\n                const int global_k = key_start + k_local;\n                float score = 0.0f;\n\n                if (global_k <= global_q && global_k < T) {\n                    // Compute dot product Q[q] · K[k]\n                    #pragma unroll\n                    for (int d = 0; d < HEAD_SIZE; d++) {\n                        score += q_vec[d] * s_KV[k_local * HEAD_SIZE + d];\n                    }\n                    score *= scale;\n                } else {\n                    // Causal mask: key position after query → -inf\n                    score = -HUGE_VALF;\n                }\n\n                // Store attention score in s_att with padding for bank conflict avoidance\n                s_att[q_local * (KEY_TILE + 1) + k_local] = score;\n            }\n        }\n        __syncthreads();\n\n        // ---- Phase 3: Load V tile into s_KV (reuse K space) ----\n        for (int i = tid; i < KEY_TILE * HEAD_SIZE; i += QUERY_TILE) {\n            const int k_local = i / HEAD_SIZE;\n            const int d       = i % HEAD_SIZE;\n            const int global_k = key_start + k_local;\n            s_KV[i] = (global_k < T) ? V_bh[global_k * t_stride + d] : 0.0f;\n        }\n        __syncthreads();\n\n        // ---- Phase 4: Online softmax + Att·V accumulation ----\n        if (valid_q) {\n            // Find tile-level max for this query row\n            float tile_max = -HUGE_VALF;\n            for (int k_local = 0; k_local < KEY_TILE; k_local++) {\n                tile_max = fmaxf(tile_max, s_att[q_local * (KEY_TILE + 1) + k_local]);\n            }\n\n            // Update running max with correction\n            float new_max = fmaxf(row_max, tile_max);\n            float old_correction = expf(row_max - new_max);\n\n            // Apply correction to running accumulators\n            row_sum *= old_correction;\n            #pragma unroll\n            for (int d = 0; d < HEAD_SIZE; d++) {\n                o_acc[d] *= old_correction;\n            }\n\n            // Process each key position in this tile\n            for (int k_local = 0; k_local < KEY_TILE; k_local++) {\n                float score    = s_att[q_local * (KEY_TILE + 1) + k_local];\n                float exp_score = expf(score - new_max);\n                row_sum += exp_score;\n\n                // Att·V: accumulate weighted V vector\n                #pragma unroll\n                for (int d = 0; d < HEAD_SIZE; d++) {\n                    o_acc[d] += exp_score * s_KV[k_local * HEAD_SIZE + d];\n                }\n            }\n\n            row_max = new_max;\n        }\n        __syncthreads();\n    }\n\n    // ---- Finalize: normalize by softmax denominator ----\n    if (valid_q) {\n        #pragma unroll\n        for (int d = 0; d < HEAD_SIZE; d++) {\n            O_bh[global_q * t_stride + d] = o_acc[d] / row_sum;\n        }\n    }\n}\n\n// ============================================================\n// Host Launch Function\n// ============================================================\n\ninline size_t compute_shared_mem_size(int head_size) {\n    // s_KV:  KEY_TILE * head_size floats\n    // s_att: QUERY_TILE * (KEY_TILE + 1) floats (padded for bank conflicts)\n    return (KEY_TILE * head_size + QUERY_TILE * (KEY_TILE + 1)) * sizeof(float);\n}\n\n// Dispatch kernel with template HEAD_SIZE\nhipError_t launch_attention_forward(\n    const float* d_Q,\n    const float* d_K,\n    const float* d_V,\n    float*       d_O,\n    int B, int T, int n_head, int head_size,\n    float scale,\n    hipStream_t stream\n) {\n    const int num_query_tiles = (T + QUERY_TILE - 1) / QUERY_TILE;\n    const int grid_size = B * n_head * num_query_tiles;\n    const size_t shared_mem = compute_shared_mem_size(head_size);\n\n    // Validate LDS fits within 64 KiB\n    if (shared_mem > 65536) {\n        fprintf(stderr, \"ERROR: shared memory %zu bytes exceeds 64 KiB LDS limit for head_size=%d\\n\",\n                shared_mem, head_size);\n        return hipErrorUnknown;\n    }\n\n    // Dispatch based on head_size (template parameter for register allocation)\n    switch (head_size) {\n        case 32:\n            attention_forward_kernel<32><<<grid_size, QUERY_TILE, shared_mem, stream>>>(\n                d_Q, d_K, d_V, d_O, B, T, n_head, scale);\n            break;\n        case 64:\n            attention_forward_kernel<64><<<grid_size, QUERY_TILE, shared_mem, stream>>>(\n                d_Q, d_K, d_V, d_O, B, T, n_head, scale);\n            break;\n        case 128:\n            attention_forward_kernel<128><<<grid_size, QUERY_TILE, shared_mem, stream>>>(\n                d_Q, d_K, d_V, d_O, B, T, n_head, scale);\n            break;\n        default:\n            fprintf(stderr, \"ERROR: unsupported head_size=%d (supported: 32, 64, 128)\\n\", head_size);\n            return hipErrorUnknown;\n    }\n\n    return hipGetLastError();\n}\n\n// ============================================================\n// QKV Projection + Output Projection via hipBLAS\n// ============================================================\n// Replaces torch::addmm from the original code.\n// QKV projection:  qkv = x @ W_qkv^T + b_qkv   [B*T, 3C] = [B*T, C] @ [C, 3C] + [3C]\n// Output projection: out = att_out @ W_proj^T + b_proj  [B*T, C] = [B*T, C] @ [C, C] + [C]\n\nstruct AttentionWeights {\n    float* d_W_qkv;      // [C, 3C] column-major (or transposed row-major)\n    float* d_b_qkv;      // [3C]\n    float* d_W_proj;      // [C, C] column-major\n    float* d_b_proj;     // [C]\n};\n\nhipError_t qkv_projection(\n    hipblasHandle_t handle,\n    const float* d_x,          // [B*T, C] row-major\n    const float* d_W,          // [C, 3C] column-major (for hipblasSgemm)\n    const float* d_bias,       // [3C]\n    float* d_out,              // [B*T, 3C]\n    int BT, int C, int C3,\n    hipStream_t stream\n) {\n    // out = 1.0 * x * W + 1.0 * bias_broadcast\n    // Step 1: Copy bias into output rows (each row of out gets bias added)\n    // For simplicity, we do: out = bias (broadcast), then out += x @ W\n    // hipblasSgemm: C = alpha*op(A)*op(B) + beta*C\n\n    const float alpha = 1.0f;\n    const float beta  = 0.0f;\n\n    // First: fill output with bias (each of BT rows gets the same bias vector)\n    // This is done by initializing d_out with bias repeated BT times\n    for (int i = 0; i < BT; i++) {\n        hipError_t err = hipMemcpyAsync(d_out + i * C3, d_bias, C3 * sizeof(float),\n                                         hipMemcpyDeviceToDevice, stream);\n        if (err != hipSuccess) return err;\n    }\n\n    // Then: out += x @ W  (beta=1.0 to accumulate on top of bias)\n    const float beta_acc = 1.0f;\n    hipblasStatus_t stat = hipblasSgemm(handle,\n        HIPBLAS_OP_N, HIPBLAS_OP_N,  // A: [BT,C], B: [C,3C]\n        C3, BT, C,                    // m=3C, n=BT, k=C\n        &alpha,\n        d_W, C3,                      // lda = 3C (column-major)\n        d_x, C,                       // ldb = C (column-major)\n        &beta_acc,\n        d_out, C3                     // ldc = 3C\n    );\n\n    return (stat == HIPBLAS_STATUS_SUCCESS) ? hipSuccess : hipErrorUnknown;\n}\n\nhipError_t output_projection(\n    hipblasHandle_t handle,\n    const float* d_att_out,    // [B*T, C] row-major\n    const float* d_W,          // [C, C] column-major\n    const float* d_bias,       // [C]\n    float* d_out,              // [B*T, C]\n    int BT, int C,\n    hipStream_t stream\n) {\n    // Same pattern as qkv_projection but with C3 = C\n    for (int i = 0; i < BT; i++) {\n        hipError_t err = hipMemcpyAsync(d_out + i * C, d_bias, C * sizeof(float),\n                                         hipMemcpyDeviceToDevice, stream);\n        if (err != hipSuccess) return err;\n    }\n\n    const float alpha = 1.0f;\n    const float beta  = 1.0f;\n    hipblasStatus_t stat = hipblasSgemm(handle,\n        HIPBLAS_OP_N, HIPBLAS_OP_N,\n        C, BT, C,\n        &alpha,\n        d_W, C,\n        d_att_out, C,\n        &beta,\n        d_out, C\n    );\n\n    return (stat == HIPBLAS_STATUS_SUCCESS) ? hipSuccess : hipErrorUnknown;\n}\n"}, "output": "Wrote file successfully.", "time": {"start": 1778430275517, "end": 1778430275525}, "title": "root/rocm-potter/kernels/attention_forward/ported.hip", "metadata": {"diagnostics": {}, "filepath": "/root/rocm-potter/kernels/attention_forward/ported.hip", "exists": false, "truncated": false}} }
