        { type: "tool", tool: "write", callID: "call_b40e41419db1462bb683a696", state: {"status": "completed", "input": {"filePath": "/root/rocm-potter/kernels/attention_forward/test_harness.cpp", "content": "#include <hip/hip_runtime.h>\n#include <hipblas/hipblas.h>\n#include <cstdio>\n#include <cstdlib>\n#include <cstring>\n#include <cmath>\n#include <random>\n#include <chrono>\n#include <vector>\n\n// Forward declaration from ported.hip\nextern hipError_t launch_attention_forward(\n    const float* d_Q, const float* d_K, const float* d_V,\n    float* d_O,\n    int B, int T, int n_head, int head_size,\n    float scale,\n    hipStream_t stream\n);\n\n// ============================================================\n// HIP Error Checking Macro\n// ============================================================\n#define HIP_CHECK(call)                                                      \\\n    do {                                                                      \\\n        hipError_t err = call;                                                \\\n        if (err != hipSuccess) {                                              \\\n            fprintf(stderr, \"HIP error at %s:%d: %s\\n\",                       \\\n                    __FILE__, __LINE__, hipGetErrorString(err));               \\\n            exit(EXIT_FAILURE);                                               \\\n        }                                                                     \\\n    } while (0)\n\n// ============================================================\n// Configuration\n// ============================================================\nstruct Config {\n    int B;\n    int T;\n    int C;\n    int n_head;\n    int head_size;\n};\n\nstatic Config correctness_config() {\n    return {2, 128, 256, 8, 32};  // B=2, T=128, C=256, n_head=8, head_size=32\n}\n\nstatic Config bench_config() {\n    return {16, 2048, 512, 8, 64};  // B=16, T=2048, C=512, n_head=8, head_size=64\n}\n\n// ============================================================\n// Data Layout: [B, T, n_head, head_size]\n// ============================================================\nstatic size_t total_elements(const Config& cfg) {\n    return (size_t)cfg.B * cfg.T * cfg.n_head * cfg.head_size;\n}\n\nstatic size_t total_bytes(const Config& cfg) {\n    return total_elements(cfg) * sizeof(float);\n}\n\n// ============================================================\n// Initialize device array with random data\n// ============================================================\nstatic void init_random_data(float* d_ptr, size_t count, hipStream_t stream) {\n    std::vector<float> h_data(count);\n    std::mt19937 gen(42);\n    std::uniform_real_distribution<float> dist(0.0f, 1.0f);\n    for (size_t i = 0; i < count; i++) {\n        h_data[i] = dist(gen);\n    }\n    HIP_CHECK(hipMemcpyAsync(d_ptr, h_data.data(), count * sizeof(float),\n                              hipMemcpyHostToDevice, stream));\n}\n\n// ============================================================\n// Check output for NaN/Inf\n// ============================================================\nstatic bool check_output_valid(const float* h_output, size_t count) {\n    int nan_count = 0;\n    int inf_count = 0;\n    for (size_t i = 0; i < count; i++) {\n        if (std::isnan(h_output[i])) nan_count++;\n        if (std::isinf(h_output[i])) inf_count++;\n    }\n    if (nan_count > 0) {\n        fprintf(stderr, \"FAIL: %d NaN values in output\\n\", nan_count);\n    }\n    if (inf_count > 0) {\n        fprintf(stderr, \"FAIL: %d Inf values in output\\n\", inf_count);\n    }\n    return (nan_count == 0 && inf_count == 0);\n}\n\n// ============================================================\n// Compute analytical FLOPs for causal attention\n// ============================================================\nstatic double compute_flops(const Config& cfg) {\n    // Q·K^T: 2 * B * n_head * T * (T+1)/2 * head_size\n    // Softmax: 5 * B * n_head * T * (T+1)/2\n    // Att·V: 2 * B * n_head * T * (T+1)/2 * head_size\n    double B_d = cfg.B;\n    double T_d = cfg.T;\n    double nh  = cfg.n_head;\n    double hs  = cfg.head_size;\n    double pairs = B_d * nh * T_d * (T_d + 1.0) / 2.0;\n    double qk_flops = 2.0 * hs * pairs;\n    double sm_flops = 5.0 * pairs;\n    double av_flops = 2.0 * hs * pairs;\n    return qk_flops + sm_flops + av_flops;\n}\n\n// ============================================================\n// Compute analytical bytes moved\n// ============================================================\nstatic double compute_bytes(const Config& cfg) {\n    // Read Q + K + V, Write O: 4 * B * T * n_head * head_size * sizeof(float)\n    return 4.0 * total_bytes(cfg);\n}\n\n// ============================================================\n// MI300X Roofline Constants (from rocm-optimization-guide)\n// ============================================================\nstatic constexpr double PEAK_FP32_GFLOPS  = 163400.0;   // GFLOP/s\nstatic constexpr double PEAK_TF32_GFLOPS  = 653700.0;\nstatic constexpr double PEAK_FP16_GFLOPS  = 1307400.0;\nstatic constexpr double PEAK_BW_GBPS      = 5325.0;     // GB/s\nstatic constexpr double RIDGE_FP32        = 30.7;       // FLOP/Byte\nstatic constexpr double RIDGE_TF32        = 122.8;\nstatic constexpr double RIDGE_FP16        = 245.3;\n\n// ============================================================\n// Correctness Test\n// ============================================================\nstatic int run_correctness(hipStream_t stream) {\n    Config cfg = correctness_config();\n    fprintf(stdout, \"=== Correctness Test ===\\n\");\n    fprintf(stdout, \"  Config: B=%d, T=%d, C=%d, n_head=%d, head_size=%d\\n\",\n            cfg.B, cfg.T, cfg.C, cfg.n_head, cfg.head_size);\n\n    size_t N = total_elements(cfg);\n    size_t bytes = total_bytes(cfg);\n    float scale = 1.0f / sqrtf((float)cfg.head_size);\n\n    // Allocate device memory\n    float *d_Q, *d_K, *d_V, *d_O;\n    HIP_CHECK(hipMalloc(&d_Q, bytes));\n    HIP_CHECK(hipMalloc(&d_K, bytes));\n    HIP_CHECK(hipMalloc(&d_V, bytes));\n    HIP_CHECK(hipMalloc(&d_O, bytes));\n\n    // Initialize with random data\n    init_random_data(d_Q, N, stream);\n    init_random_data(d_K, N, stream);\n    init_random_data(d_V, N, stream);\n    HIP_CHECK(hipMemsetAsync(d_O, 0, bytes, stream));\n    HIP_CHECK(hipStreamSynchronize(stream));\n\n    // Launch kernel\n    HIP_CHECK(launch_attention_forward(d_Q, d_K, d_V, d_O,\n                                       cfg.B, cfg.T, cfg.n_head, cfg.head_size,\n                                       scale, stream));\n    HIP_CHECK(hipStreamSynchronize(stream));\n\n    // Copy output to host and check\n    std::vector<float> h_output(N);\n    HIP_CHECK(hipMemcpy(h_output.data(), d_O, bytes, hipMemcpyDeviceToHost));\n\n    bool valid = check_output_valid(h_output.data(), N);\n\n    // Cleanup\n    HIP_CHECK(hipFree(d_Q));\n    HIP_CHECK(hipFree(d_K));\n    HIP_CHECK(hipFree(d_V));\n    HIP_CHECK(hipFree(d_O));\n\n    if (valid) {\n        fprintf(stdout, \"  Result: PASS (no NaN/Inf, no crash)\\n\");\n        return 0;\n    } else {\n        fprintf(stdout, \"  Result: FAIL\\n\");\n        return 1;\n    }\n}\n\n// ============================================================\n// Performance Benchmark\n// ============================================================\nstatic int run_benchmark(hipStream_t stream, int iterations) {\n    Config cfg = bench_config();\n    fprintf(stdout, \"\\n=== Benchmark: attention_forward_kernel ===\\n\");\n    fprintf(stdout, \"  Config: B=%d, T=%d, C=%d, n_head=%d, head_size=%d\\n\",\n            cfg.B, cfg.T, cfg.C, cfg.n_head, cfg.head_size);\n    fprintf(stdout, \"  Iterations: %d (2 warmup excluded)\\n\", iterations);\n\n    size_t N = total_elements(cfg);\n    size_t bytes = total_bytes(cfg);\n    float scale = 1.0f / sqrtf((float)cfg.head_size);\n\n    // Allocate device memory\n    float *d_Q, *d_K, *d_V, *d_O;\n    HIP_CHECK(hipMalloc(&d_Q, bytes));\n    HIP_CHECK(hipMalloc(&d_K, bytes));\n    HIP_CHECK(hipMalloc(&d_V, bytes));\n    HIP_CHECK(hipMalloc(&d_O, bytes));\n\n    // Initialize with random data\n    init_random_data(d_Q, N, stream);\n    init_random_data(d_K, N, stream);\n    init_random_data(d_V, N, stream);\n    HIP_CHECK(hipMemsetAsync(d_O, 0, bytes, stream));\n    HIP_CHECK(hipStreamSynchronize(stream));\n\n    // Create events for timing\n    hipEvent_t start, stop;\n    HIP_CHECK(hipEventCreate(&start));\n    HIP_CHECK(hipEventCreate(&stop));\n\n    // Warmup (2 iterations, not counted)\n    for (int i = 0; i < 2; i++) {\n        HIP_CHECK(launch_attention_forward(d_Q, d_K, d_V, d_O,\n                                           cfg.B, cfg.T, cfg.n_head, cfg.head_size,\n                                           scale, stream));\n    }\n    HIP_CHECK(hipStreamSynchronize(stream));\n\n    // Timed iterations\n    HIP_CHECK(hipEventRecord(start, stream));\n    for (int i = 0; i < iterations; i++) {\n        HIP_CHECK(launch_attention_forward(d_Q, d_K, d_V, d_O,\n                                           cfg.B, cfg.T, cfg.n_head, cfg.head_size,\n                                           scale, stream));\n    }\n    HIP_CHECK(hipEventRecord(stop, stream));\n    HIP_CHECK(hipEventSynchronize(stop));\n\n    float elapsed_ms = 0.0f;\n    HIP_CHECK(hipEventElapsedTime(&elapsed_ms, start, stop));\n\n    // Compute metrics\n    double total_time_sec = (elapsed_ms / 1000.0) / iterations;  // avg per iteration\n    double flops = compute_flops(cfg);\n    double bytes_moved = compute_bytes(cfg);\n    double ai = flops / bytes_moved;\n    double achieved_gflops = (flops / 1e9) / total_time_sec;\n    double achieved_bw_gbps = (bytes_moved / 1e9) / total_time_sec;\n    double compute_eff = achieved_gflops / PEAK_FP32_GFLOPS * 100.0;\n    double bw_eff = achieved_bw_gbps / PEAK_BW_GBPS * 100.0;\n    const char* bottleneck = (ai > RIDGE_FP32) ? \"COMPUTE-BOUND\" : \"MEMORY-BOUND\";\n    const char* ai_compare = (ai > RIDGE_FP32) ? \">\" : \"<\";\n\n    // NERSC Roofline Report\n    fprintf(stdout, \"\\n\");\n    fprintf(stdout, \"  ── Timing ──\\n\");\n    fprintf(stdout, \"  Kernel Time:     %.3f ms (avg over %d iterations)\\n\",\n            elapsed_ms / iterations, iterations);\n    fprintf(stdout, \"  ── Analytical Roofline ──\\n\");\n    fprintf(stdout, \"  Analytical FLOPs:     %.3e\\n\", flops);\n    fprintf(stdout, \"  Analytical Bytes:     %.3e\\n\", bytes_moved);\n    fprintf(stdout, \"  Analytical AI:        %.1f FLOP/Byte\\n\", ai);\n    fprintf(stdout, \"  ── Achieved Performance ──\\n\");\n    fprintf(stdout, \"  Achieved GFLOP/s:     %.1f\\n\", achieved_gflops);\n    fprintf(stdout, \"  Achieved BW:          %.1f GB/s\\n\", achieved_bw_gbps);\n    fprintf(stdout, \"  ── Hardware Peaks (MI300X) ──\\n\");\n    fprintf(stdout, \"  Peak FP32:            %.1f GFLOP/s\\n\", PEAK_FP32_GFLOPS);\n    fprintf(stdout, \"  Peak TF32 (MFMA):     %.1f GFLOP/s\\n\", PEAK_TF32_GFLOPS);\n    fprintf(stdout, \"  Peak FP16 (MFMA):     %.1f GFLOP/s\\n\", PEAK_FP16_GFLOPS);\n    fprintf(stdout, \"  Peak BW:              %.1f GB/s\\n\", PEAK_BW_GBPS);\n    fprintf(stdout, \"  Ridge Point AI (FP32):  %.1f FLOP/Byte\\n\", RIDGE_FP32);\n    fprintf(stdout, \"  Ridge Point AI (TF32):  %.1f FLOP/Byte\\n\", RIDGE_TF32);\n    fprintf(stdout, \"  Ridge Point AI (FP16):  %.1f FLOP/Byte\\n\", RIDGE_FP16);\n    fprintf(stdout, \"  ── Efficiency ──\\n\");\n    fprintf(stdout, \"  Compute Efficiency:   %.1f%% of peak FP32\\n\", compute_eff);\n    fprintf(stdout, \"  Bandwidth Efficiency: %.1f%% of peak BW\\n\", bw_eff);\n    fprintf(stdout, \"  Bottleneck:           %s (AI %.1f %s ridge %.1f)\\n\",\n            bottleneck, ai, ai_compare, RIDGE_FP32);\n\n    // Quick validity check on benchmark output\n    std::vector<float> h_output(N);\n    HIP_CHECK(hipMemcpy(h_output.data(), d_O, bytes, hipMemcpyDeviceToHost));\n    bool valid = check_output_valid(h_output.data(), N);\n    if (!valid) {\n        fprintf(stdout, \"\\n  WARNING: Output contains NaN/Inf — benchmark results unreliable\\n\");\n    }\n\n    // Cleanup\n    HIP_CHECK(hipEventDestroy(start));\n    HIP_CHECK(hipEventDestroy(stop));\n    HIP_CHECK(hipFree(d_Q));\n    HIP_CHECK(hipFree(d_K));\n    HIP_CHECK(hipFree(d_V));\n    HIP_CHECK(hipFree(d_O));\n\n    return valid ? 0 : 1;\n}\n\n// ============================================================\n// Main\n// ============================================================\nint main(int argc, char* argv[]) {\n    bool correctness = false;\n    bool bench = false;\n    int iterations = 50;\n\n    for (int i = 1; i < argc; i++) {\n        if (strcmp(argv[i], \"--correctness\") == 0) correctness = true;\n        if (strcmp(argv[i], \"--bench\") == 0) bench = true;\n        if (strcmp(argv[i], \"--iterations\") == 0 && i + 1 < argc) {\n            iterations = atoi(argv[++i]);\n        }\n    }\n\n    // Default: correctness mode\n    if (!correctness && !bench) correctness = true;\n\n    // Set device\n    int device_id = 0;\n    HIP_CHECK(hipSetDevice(device_id));\n\n    hipDeviceProp_t prop;\n    HIP_CHECK(hipGetDeviceProperties(&prop, device_id));\n    fprintf(stdout, \"Device: %s (arch: %s)\\n\", prop.name, prop.gcnArchName);\n\n    // Create stream\n    hipStream_t stream;\n    HIP_CHECK(hipStreamCreate(&stream));\n\n    int result = 0;\n    if (correctness) {\n        result |= run_correctness(stream);\n    }\n    if (bench) {\n        result |= run_benchmark(stream, iterations);\n    }\n\n    HIP_CHECK(hipStreamDestroy(stream));\n\n    return result;\n}\n"}, "output": "Wrote file successfully.", "time": {"start": 1778430534397, "end": 1778430534403}, "title": "root/rocm-potter/kernels/attention_forward/test_harness.cpp", "metadata": {"diagnostics": {}, "filepath": "/root/rocm-potter/kernels/attention_forward/test_harness.cpp", "exists": false, "truncated": false}} }
